     1→/**
     2→ * global.css — Base Element Defaults
     3→ * =====================================
     4→ * Reusable styles: reset, typography, links, buttons, forms, 12-column grid.
     5→ * Mobile-first: base styles target smallest screen; min-width queries add complexity upward.
     6→ *
     7→ * Load order: after fonts.css, before components.css.
     8→ */
     9→
    10→@charset "UTF-8";
    11→
    12→/* ===== BOX MODEL RESET ===== */
    13→*,
    14→*::before,
    15→*::after {
    16→    box-sizing: border-box;
    17→    margin: 0;
    18→    padding: 0;
    19→}
    20→
    21→/* ===== HTML & BODY ===== */
    22→html {
    23→    /* Do not override font-size — preserve browser default (1rem = 16px).
    24→       Users who change their browser font size deserve that choice. */
    25→    height: 100%;
    26→}
    27→
    28→body {
    29→    align-items: center;
    30→    background-color: var(--color-bg);
    31→    color: var(--color-text);
    32→    display: flex;
    33→    font-family: var(--font-family-body, Arial, Helvetica, sans-serif);
    34→    font-size: var(--font-size-body, 1em);
    35→    justify-content: center;
    36→    line-height: 1.5;
    37→    min-height: 100%;
    38→    position: relative;
    39→}
    40→
    41→/* Responsive line height: slightly looser on larger screens */
    42→@media (min-width: 768px) {
    43→    body {
    44→        line-height: 1.7;
    45→    }
    46→}
    47→
    48→/* ===== IMAGES ===== */
    49→/* Prevent images from overflowing their containers */
    50→img,
    51→video {
    52→    display: block;
    53→    height: auto;
    54→    max-width: 100%;
    55→}
    56→
    57→/* ===== CANVAS ===== */
    58→/* Hidden canvas used by favicon-animator.js */
    59→canvas {
    60→    height: 32px;
    61→    position: absolute;
    62→    visibility: hidden;
    63→    width: 32px;
    64→}
    65→
    66→/* ===== BASE TYPOGRAPHY ===== */
    67→h1 { font-size: var(--font-size-h1, 2em); }
    68→h2 { font-size: var(--font-size-h2, 1.5em); }
    69→h3 { font-size: var(--font-size-h3, 1.25em); }
    70→
    71→p {
    72→    font-size: var(--font-size-body, 1em);
    73→    line-height: inherit;
    74→    margin-bottom: var(--space-md);
    75→}
    76→
    77→p:last-child {
    78→    margin-bottom: 0;
    79→}
    80→
    81→/* ===== LINKS ===== */
    82→a {
    83→    color: inherit;
    84→    text-decoration: none;
    85→    transition: color var(--transition-fast) ease;
    86→}
    87→
    88→a:hover {
    89→    color: var(--color-text-muted);
    90→}
    91→
    92→a:focus-visible {
    93→    color: var(--color-text-muted);
    94→    outline: 2px solid var(--color-focus);
    95→    outline-offset: 2px;
    96→}
    97→
    98→/* Button-like links — never underline */
    99→a[class*="btn"],
   100→a[role="button"] {
   101→    text-decoration: none;
   102→}
   103→
   104→/* ===== BUTTONS ===== */
   105→button {
   106→    background: none;
   107→    border: none;
   108→    cursor: pointer;
   109→    font: inherit;
   110→    text-decoration: none;
   111→}
   112→
   113→button:disabled {
   114→    cursor: not-allowed;
   115→    opacity: 0.5;
   116→}
   117→
   118→/* .btn — base button component class */
   119→.btn {
   120→    align-items: center;
   121→    border: none;
   122→    border-radius: var(--border-radius-sm);
   123→    cursor: pointer;
   124→    display: inline-flex;
   125→    font-family: inherit;
   126→    font-size: var(--font-size-body);
   127→    font-weight: bold;
   128→    justify-content: center;
   129→    line-height: 1;
   130→    min-height: 2.75rem;    /* 44px minimum touch target */
   131→    padding: var(--space-sm) var(--space-lg);
   132→    text-decoration: none;
   133→    transition:
   134→        background-color var(--transition-fast) ease,
   135→        color var(--transition-fast) ease,
   136→        opacity var(--transition-fast) ease;
   137→}
   138→
   139→.btn-primary {
   140→    background: var(--color-btn-primary);
   141→    color: var(--color-text-on-btn-primary);
   142→}
   143→
   144→.btn-primary:hover  { background: var(--color-btn-primary-hover); color: var(--color-text-on-btn-primary); }
   145→.btn-primary:active { background: var(--color-btn-primary-active); }
   146→
   147→.btn-secondary {
   148→    background: var(--color-btn-secondary);
   149→    color: var(--color-text-on-btn-secondary);
   150→}
   151→
   152→.btn-secondary:hover  { background: var(--color-btn-secondary-hover); color: var(--color-text-on-btn-secondary); }
   153→.btn-secondary:active { background: var(--color-btn-secondary-active); }
   154→
   155→.btn:focus-visible {
   156→    outline: 2px solid var(--color-focus);
   157→    outline-offset: 2px;
   158→}
   159→
   160→.btn:disabled {
   161→    cursor: not-allowed;
   162→    opacity: 0.5;
   163→}
   164→
   165→/* ===== FORMS ===== */
   166→label {
   167→    color: var(--color-text-muted);
   168→    cursor: pointer;
   169→    display: block;
   170→    font-size: var(--font-size-sm);
   171→    margin-bottom: var(--space-xs);
   172→}
   173→
   174→/* Text-like inputs */
   175→input:not([type="checkbox"]):not([type="radio"]):not([type="submit"]):not([type="button"]):not([type="reset"]),
   176→textarea,
   177→select {
   178→    background: var(--color-input-bg);
   179→    border: 1px solid var(--color-input-border);
   180→    border-radius: var(--border-radius-sm);
   181→    color: var(--color-input-text);
   182→    font-family: inherit;
   183→    font-size: var(--font-size-body);
   184→    line-height: 1.5;
   185→    padding: var(--space-sm) var(--space-md);
   186→    transition:
   187→        border-color var(--transition-fast) ease,
   188→        box-shadow var(--transition-fast) ease;
   189→    width: 100%;
   190→}
   191→
   192→input:not([type="checkbox"]):not([type="radio"]):not([type="submit"]):not([type="button"]):not([type="reset"]):focus,
   193→textarea:focus,
   194→select:focus {
   195→    border-color: var(--color-input-border-focus);
   196→    box-shadow: 0 0 0 3px var(--color-accent);
   197→    outline: none;
   198→}
   199→
   200→input::placeholder,
   201→textarea::placeholder {
   202→    color: var(--color-input-placeholder);
   203→}
   204→
   205→input:disabled,
   206→textarea:disabled,
   207→select:disabled {
   208→    background: var(--color-input-bg-disabled);
   209→    cursor: not-allowed;
   210→    opacity: 0.7;
   211→}
   212→
   213→/* ===== CHECKBOXES & RADIOS ===== */
   214→input[type="checkbox"],
   215→input[type="radio"] {
   216→    appearance: none;
   217→    background-color: var(--color-input-bg);
   218→    border: var(--border-width) solid var(--color-input-border);
   219→    cursor: pointer;
   220→    display: inline-grid;
   221→    flex-shrink: 0;
   222→    height: 1.125rem;
   223→    margin: 0;
   224→    place-content: center;
   225→    transition:
   226→        background-color var(--transition-fast) ease,
   227→        border-color var(--transition-fast) ease,
   228→        box-shadow var(--transition-fast) ease;
   229→    width: 1.125rem;
   230→}
   231→
   232→input[type="checkbox"] { border-radius: var(--border-radius-sm); }
   233→input[type="radio"]    { border-radius: 50%; }
   234→
   235→input[type="checkbox"]::before,
   236→input[type="radio"]::before {
   237→    content: "";
   238→    transform: scale(0);
   239→    transition: transform var(--transition-fast) var(--ease-in-out);
   240→}
   241→
   242→input[type="checkbox"]::before {
   243→    background-color: var(--color-text-on-btn-primary);
   244→    clip-path: polygon(14% 44%, 0 65%, 50% 100%, 100% 16%, 80% 0%, 43% 62%);
   245→    height: 0.625rem;
   246→    width: 0.625rem;
   247→}
   248→
   249→input[type="radio"]::before {
   250→    background-color: var(--color-text-on-btn-primary);
   251→    border-radius: 50%;
   252→    height: 0.4375rem;
   253→    width: 0.4375rem;
   254→}
   255→
   256→input[type="checkbox"]:checked,
   257→input[type="radio"]:checked {
   258→    background-color: var(--color-btn-primary);
   259→    border-color: var(--color-btn-primary);
   260→}
   261→
   262→input[type="checkbox"]:checked::before,
   263→input[type="radio"]:checked::before {
   264→    transform: scale(1);
   265→}
   266→
   267→input[type="checkbox"]:focus-visible,
   268→input[type="radio"]:focus-visible {
   269→    border-color: var(--color-input-border-focus);
   270→    box-shadow: 0 0 0 3px var(--color-accent);
   271→    outline: none;
   272→}
   273→
   274→input[type="checkbox"]:disabled,
   275→input[type="radio"]:disabled {
   276→    background-color: var(--color-input-bg-disabled);
   277→    cursor: not-allowed;
   278→    opacity: 0.7;
   279→}
   280→
   281→/* .form-check — inline label + checkbox/radio pair */
   282→.form-check {
   283→    align-items: center;
   284→    cursor: pointer;
   285→    display: inline-flex;
   286→    gap: var(--space-sm);
   287→}
   288→
   289→.form-check-label {
   290→    color: var(--color-text);
   291→    cursor: pointer;
   292→    font-size: var(--font-size-body);
   293→    line-height: 1.5;
   294→    margin-bottom: 0;
   295→}
   296→
   297→.form-check:has(input:disabled) {
   298→    cursor: not-allowed;
   299→    opacity: 0.7;
   300→}
   301→
   302→/* ===== 12-COLUMN PAGE GRID ===== */
   303→/* Mobile-first: all columns full-width by default, expand at breakpoints.
   304→   The clock homepage bypasses this — use .container/.row/.col-* on other pages only. */
