    function loop(now) {
        rafId = requestAnimationFrame(loop);
        if (now - lastTick < FRAME_INTERVAL_MS) return;
        lastTick = now;
        drawFrame();
    }

    // ── Pause / resume on tab visibility ──────────────────────────────────────

    function pause() {
        if (rafId !== null) {
            cancelAnimationFrame(rafId);
            rafId = null;
        }
    }

    function resume() {
        if (rafId === null) {
            lastTick = 0; // let first frame fire immediately
            rafId = requestAnimationFrame(loop);
        }
    }

    // ── Init ──────────────────────────────────────────────────────────────────

    function init() {
        canvas        = document.createElement('canvas');
        canvas.width  = CANVAS_SIZE;
        canvas.height = CANVAS_SIZE;
        ctx           = canvas.getContext('2d');
        if (!ctx) return false;

        // Remove all static favicon links so no competing icon can override
        // the animated one. Browsers (especially Chrome) give ICO/SVG declared
        // in HTML priority over a mutated href — injecting a fresh element is
        // the only reliable way to take control of the tab icon.
        document.querySelectorAll('link[rel="icon"], link[rel="shortcut icon"]').forEach(el => el.remove());

        favicon      = document.createElement('link');
        favicon.rel  = 'icon';
        favicon.type = 'image/png';
        document.head.appendChild(favicon);

        const gradient = ctx.createLinearGradient(0, 0, CANVAS_SIZE, CANVAS_SIZE);
        gradient.addColorStop(0, GRADIENT_START);
        gradient.addColorStop(1, GRADIENT_END);
        ctx.strokeStyle = gradient;
        ctx.lineWidth   = 16;

        document.addEventListener('visibilitychange', () => {
            document.hidden ? pause() : resume();
        });

        resume();
        return true;
    }

    return { init };
})();

