     1→/**
     2→ * controls.js — Clock Controls Panel
     3→ * =====================================
     4→ * Handles all form interaction on clock-controls.html:
     5→ * - Restores saved values from localStorage on load
     6→ * - Toggles section visibility when mode radio changes
     7→ * - Writes settings to localStorage on every input event
     8→ * - Computes countdown end timestamp on Start / Reset click
     9→ *
    10→ * localStorage keys (read by clock.js on the main page):
    11→ *   clk_mode           — "clock" or "countdown"
    12→ *   clk_hours          — UTC offset integer string (e.g. "1" for UTC+1)
    13→ *   clk_countdown_time — Duration "MM:SS" string (e.g. "05:00")
    14→ *   clk_countdown_end  — Unix timestamp ms (absolute countdown end time)
    15→ */
    16→
    17→(function () {
    18→    'use strict';
    19→
    20→    const ls = { get: k => localStorage.getItem(k), set: (k, v) => localStorage.setItem(k, v) };
    21→
    22→    // ── Restore saved values ────────────────────────────────────────────
    23→    const rawMode    = ls.get('clk_mode');
    24→    const savedMode  = (rawMode === 'clock' || rawMode === 'countdown') ? rawMode : 'clock';
    25→    const savedHours = ls.get('clk_hours')           || '0';
    26→    const savedTime  = ls.get('clk_countdown_time')  || '05:00';
    27→
    28→    document.querySelector(`input[value="${savedMode}"]`).checked = true;
    29→    document.getElementById('hours').value          = savedHours;
    30→    document.getElementById('countdown-time').value = savedTime;
    31→
    32→    // ── Section visibility ──────────────────────────────────────────────
    33→    function updateSections() {
    34→        const mode = document.querySelector('input[name="mode"]:checked').value;
    35→        document.getElementById('section-clock').classList.toggle('is-hidden', mode !== 'clock');
    36→        document.getElementById('section-countdown').classList.toggle('is-hidden', mode !== 'countdown');
    37→        document.getElementById('lbl-clock').classList.toggle('is-active', mode === 'clock');
    38→        document.getElementById('lbl-countdown').classList.toggle('is-active', mode === 'countdown');
    39→    }
    40→    updateSections();
    41→
    42→    // ── Event listeners ─────────────────────────────────────────────────
    43→    document.querySelectorAll('input[name="mode"]').forEach(r => {
    44→        r.addEventListener('change', () => {
    45→            ls.set('clk_mode', r.value);
    46→            updateSections();
    47→        });
    48→    });
    49→
    50→    document.getElementById('hours').addEventListener('input', e => {
    51→        ls.set('clk_hours', e.target.value);
    52→    });
    53→
    54→    document.getElementById('countdown-time').addEventListener('input', e => {
    55→        ls.set('clk_countdown_time', e.target.value);
    56→    });
    57→
    58→    // ── Start / Reset countdown ──────────────────────────────────────────
    59→    document.getElementById('start-btn').addEventListener('click', () => {
    60→        const raw   = document.getElementById('countdown-time').value.trim() || '05:00';
    61→        const parts = raw.split(':');
    62→        const mm    = Math.min(99, parseInt(parts[0], 10) || 0);
    63→        const ss    = Math.min(59, parseInt(parts[1], 10) || 0);
    64→        const totalMs = (mm * 60 + ss) * 1000;
    65→
    66→        ls.set('clk_countdown_time', `${String(mm).padStart(2, '0')}:${String(ss).padStart(2, '0')}`);
    67→        ls.set('clk_countdown_end', Date.now() + totalMs);
    68→        ls.set('clk_mode', 'countdown');
    69→
    70→        document.querySelector('input[value="countdown"]').checked = true;
    71→        updateSections();
    72→
    73→        const endTime = new Date(Date.now() + totalMs);
    74→        document.getElementById('status').textContent =
    75→            `Started — ends at ${endTime.toLocaleTimeString()}`;
    76→    });
    77→}());
    78→

