     1→/**
     2→ * logger.js — Development Logger
     3→ * ==================================
     4→ * Structured activity logger for build-time diagnostics.
     5→ * Entirely separate from application code — safe to include or exclude
     6→ * without affecting any clock or UI functionality.
     7→ *
     8→ * Entries are buffered in memory and flushed to sessionStorage only on
     9→ * beforeunload (or manually via Logger.flush()), avoiding synchronous
    10→ * storage I/O on every log call.
    11→ *
    12→ * Storage:
    13→ *   - Active session logs → sessionStorage (cleared on tab close)
    14→ *   - Summary snapshot    → localStorage (persists, written on beforeunload)
    15→ *
    16→ * Usage:
    17→ *   Logger.log('section', 'message', { optional: 'data' });
    18→ *   Logger.time('hero-image');
    19→ *   Logger.timeEnd('hero-image');
    20→ *   Logger.flush();   // write buffer to sessionStorage now
    21→ *   Logger.dump();    // print all entries to console
    22→ *   Logger.clear();   // wipe buffer + sessionStorage
    23→ */
    24→
    25→const Logger = (() => {
    26→    'use strict';
    27→
    28→    const SESSION_KEY = 'ap_dev_log';
    29→    const PERSIST_KEY = 'ap_dev_log_summary';
    30→
    31→    // In-memory buffer — flushed to sessionStorage only on unload
    32→    const _buf = [];
    33→    const _timers = {};
    34→
    35→    // ── Helpers ───────────────────────────────────────────────────────────────
    36→
    37→    function timestamp() {
    38→        return new Date().toISOString();
    39→    }
    40→
    41→    // ── Public API ─────────────────────────────────────────────────────────────
    42→
    43→    /**
    44→     * Log a named event with an optional data payload.
    45→     * @param {string} section - Logical category (e.g. 'init', 'clock', 'storage')
    46→     * @param {string} message - Human-readable description
    47→     * @param {*}      [data]  - Optional structured data
    48→     */
    49→    function log(section, message, data) {
    50→        const entry = { ts: timestamp(), section, message };
    51→        if (data !== undefined) entry.data = data;
    52→        _buf.push(entry);
    53→        // No synchronous storage write here — see flush()
    54→    }
    55→
    56→    /**
    57→     * Start a named performance timer.
    58→     * @param {string} name - Timer identifier
    59→     */
    60→    function time(name) {
    61→        _timers[name] = performance.now();
    62→        log('timer', `start: ${name}`);
    63→    }
    64→
    65→    /**
    66→     * Stop a named timer and log elapsed milliseconds.
    67→     * @param {string} name - Timer identifier
    68→     * @returns {number|null} Elapsed ms, or null if timer was not started
    69→     */
    70→    function timeEnd(name) {
    71→        if (!(name in _timers)) {
    72→            console.warn(`[Logger] timeEnd called for unknown timer: "${name}"`);
    73→            return null;
    74→        }
    75→        const elapsed = +(performance.now() - _timers[name]).toFixed(2);
    76→        delete _timers[name];
    77→        log('timer', `end: ${name}`, { elapsed_ms: elapsed });
    78→        return elapsed;
    79→    }
    80→
    81→    /**
    82→     * Flush in-memory buffer to sessionStorage.
    83→     * Called automatically on beforeunload; call manually if needed.
    84→     */
    85→    function flush() {
    86→        try {
    87→            sessionStorage.setItem(SESSION_KEY, JSON.stringify(_buf));
    88→        } catch (e) {
    89→            console.warn('[Logger] sessionStorage flush failed:', e.message);
    90→        }
    91→    }
    92→
    93→    /**
    94→     * Print all buffered log entries to the browser console.
    95→     * @returns {Array} The full entry array
    96→     */
    97→    function dump() {
    98→        console.group('[Logger] Session log dump');
    99→        _buf.forEach(e => console.log(`[${e.ts}] [${e.section}] ${e.message}`, e.data || ''));
   100→        console.groupEnd();
   101→        return _buf;
   102→    }
   103→
   104→    /**
   105→     * Clear the in-memory buffer and sessionStorage.
   106→     */
   107→    function clear() {
   108→        _buf.length = 0;
   109→        try { sessionStorage.removeItem(SESSION_KEY); } catch { /* noop */ }
   110→    }
   111→
   112→    // ── Flush on unload ────────────────────────────────────────────────────────
   113→
   114→    window.addEventListener('beforeunload', () => {
   115→        flush();
   116→        try {
   117→            const summary = {
   118→                saved_at: timestamp(),
   119→                url:      location.href,
   120→                count:    _buf.length,
   121→                entries:  _buf,
   122→            };
   123→            localStorage.setItem(PERSIST_KEY, JSON.stringify(summary));
   124→        } catch { /* noop — storage may be full or restricted */ }
   125→    });
   126→
   127→    // ── Self-test on init (buffered, zero storage I/O) ────────────────────────
   128→
   129→    (function selfTest() {
   130→        log('logger', 'Logger initialised', { mode: 'buffered' });
   131→
   132→        try {
   133→            localStorage.setItem('_ap_test', '1');
   134→            localStorage.removeItem('_ap_test');
   135→            log('storage', 'localStorage: available');
   136→        } catch {
   137→            log('storage', 'localStorage: unavailable or blocked');
   138→        }
   139→
   140→        try {
   141→            sessionStorage.setItem('_ap_test', '1');
   142→            sessionStorage.removeItem('_ap_test');
   143→            log('storage', 'sessionStorage: available');
   144→        } catch {
   145→            log('storage', 'sessionStorage: unavailable or blocked');
   146→        }
   147→
   148→        const navEntry = performance.getEntriesByType('navigation')[0];
   149→        if (navEntry) {
   150→            log('perf', 'navigation timing', {
   151→                domContentLoaded_ms: +navEntry.domContentLoadedEventEnd.toFixed(2),
   152→                load_ms:             +navEntry.loadEventEnd.toFixed(2),
   153→                ttfb_ms:             +(navEntry.responseStart - navEntry.requestStart).toFixed(2),
   154→            });
   155→        }
   156→    }());
   157→
   158→    return { log, time, timeEnd, flush, dump, clear };
   159→
   160→})();
   161→

