    20→    --ctrl-accent:       #415e70;
    21→    --ctrl-accent-hover: #527a96;
    22→    --ctrl-accent-active:#2e4452;
    23→    --ctrl-status:       #8ab4d4;
    24→    --ctrl-link:         #8ab4d4;
    25→    --ctrl-link-hover:   #b0cfea;
    26→    --ctrl-danger:       #ff1b0e;
    27→}
    28→
    29→/* ===== RESET ===== */
    30→*,
    31→*::before,
    32→*::after {
    33→    box-sizing: border-box;
    34→    margin: 0;
    35→    padding: 0;
    36→}
    37→
    38→/* ===== BASE ===== */
    39→body {
    40→    align-items: flex-start;
    41→    background: var(--ctrl-bg);
    42→    color: var(--ctrl-text);
    43→    display: flex;
    44→    flex-direction: column;
    45→    font-family: 'Courier New', Courier, monospace;
    46→    font-size: 0.875em;
    47→    justify-content: flex-start;
    48→    line-height: 1.6;
    49→    min-height: 100dvh;
    50→    padding: 3rem 1.5rem 4rem;
    51→}
    52→
    53→/* ===== LAYOUT ===== */
    54→.panel {
    55→    width: 100%;
    56→    max-width: 460px;
    57→}
    58→
    59→/* ===== NAV ===== */
    60→.panel-nav {
    61→    align-items: center;
    62→    border-bottom: 1px solid var(--ctrl-border);
    63→    display: flex;
    64→    justify-content: space-between;
    65→    margin-bottom: 2.5rem;
    66→    padding-bottom: 1rem;
    67→}
    68→
    69→.panel-nav-link {
    70→    color: var(--ctrl-link);
    71→    font-size: 0.8em;
    72→    letter-spacing: 0.06em;
    73→    text-decoration: none;
    74→    transition: color 0.2s ease;
    75→}
    76→
    77→.panel-nav-link:hover {
    78→    color: var(--ctrl-link-hover);
    79→}
    80→
    81→.panel-nav-link:focus-visible {
    82→    outline: 2px solid var(--ctrl-border-focus);
    83→    outline-offset: 2px;
    84→}
    85→
    86→.panel-nav-id {
    87→    color: var(--ctrl-text-dim);
    88→    font-size: 0.7em;
    89→    letter-spacing: 0.14em;
    90→    text-transform: uppercase;
    91→}
    92→
    93→/* ===== HEADINGS ===== */
    94→.panel-title {
    95→    color: var(--ctrl-text-muted);
    96→    font-size: 0.85em;
    97→    letter-spacing: 0.18em;
    98→    margin-bottom: 2rem;
    99→    text-transform: uppercase;
   100→}
   101→
   102→.section-title {
   103→    border-bottom: 1px solid var(--ctrl-border);
   104→    color: var(--ctrl-text-dim);
   105→    font-size: 0.65em;
   106→    letter-spacing: 0.16em;
   107→    margin-bottom: 1rem;
   108→    padding-bottom: 0.5rem;
   109→    text-transform: uppercase;
   110→}
   111→
   112→/* ===== SECTIONS ===== */
   113→.ctrl-section {
   114→    background: var(--ctrl-bg-section);
   115→    border: 1px solid var(--ctrl-border);
   116→    border-radius: 4px;
   117→    margin-bottom: 1rem;
   118→    padding: 1.25rem 1.5rem;
   119→}
   120→
   121→/* ===== RADIO LABELS ===== */
   122→/* Wrapping label pattern — input nested inside label for implicit association */
   123→.ctrl-radio-label {
   124→    align-items: center;
   125→    color: var(--ctrl-text-muted);
   126→    cursor: pointer;
   127→    display: flex;
   128→    font-size: 0.9em;
   129→    gap: 0.6rem;
   130→    margin-bottom: 0.4rem;
   131→    transition: color 0.15s ease;
   132→}
   133→
   134→.ctrl-radio-label:hover,
   135→.ctrl-radio-label.is-active {
   136→    color: var(--ctrl-text);
   137→}
   138→
   139→input[type="radio"] {
   140→    accent-color: var(--ctrl-accent);
   141→    cursor: pointer;
   142→    height: 14px;
   143→    width: 14px;
   144→}
   145→
   146→/* ===== FIELD ROWS ===== */
   147→.ctrl-field {
   148→    align-items: center;
   149→    display: flex;
   150→    gap: 1rem;
   151→    margin-bottom: 0.75rem;
   152→}
   153→
   154→.ctrl-field-label {
   155→    color: var(--ctrl-text-muted);
   156→    font-size: 0.85em;
   157→    min-width: 9rem;
   158→}
   159→
   160→/* ===== TEXT & NUMBER INPUTS ===== */
   161→input[type="number"],
   162→input[type="text"] {
   163→    background: var(--ctrl-bg-input);
   164→    border: 1px solid rgba(242, 249, 255, 0.18);
   165→    border-radius: 3px;
   166→    color: var(--ctrl-text);
   167→    font-family: inherit;
   168→    font-size: inherit;
   169→    padding: 0.4rem 0.7rem;
   170→    transition:
   171→        border-color 0.2s ease,
   172→        box-shadow 0.2s ease;
   173→    width: 8rem;
   174→}
   175→
   176→input[type="number"]:focus,
   177→input[type="text"]:focus {
   178→    border-color: var(--ctrl-border-focus);
   179→    box-shadow: 0 0 0 2px rgb(138 180 212 / 0.18);
   180→    outline: none;
   181→}
   182→
   183→/* ===== BUTTON ===== */
   184→.ctrl-btn {
   185→    align-items: center;
   186→    background: var(--ctrl-accent);
   187→    border: none;
   188→    border-radius: 3px;
   189→    color: #ffffff;
   190→    cursor: pointer;
   191→    display: inline-flex;
   192→    font-family: inherit;
   193→    font-size: 0.85em;
   194→    gap: 0.4rem;
   195→    letter-spacing: 0.06em;
   196→    margin-top: 0.75rem;
   197→    padding: 0.55rem 1.4rem;
   198→    text-decoration: none;
   199→    transition: background 0.2s ease;
   200→}
   201→
   202→.ctrl-btn:hover  { background: var(--ctrl-accent-hover); }
   203→.ctrl-btn:active { background: var(--ctrl-accent-active); }
   204→
   205→.ctrl-btn:focus-visible {
   206→    outline: 2px solid var(--ctrl-border-focus);
   207→    outline-offset: 2px;
   208→}
   209→
   210→/* ===== NOTES ===== */
   211→.ctrl-note {
   212→    color: var(--ctrl-text-dim);
   213→    font-size: 0.72em;
   214→    line-height: 1.5;
   215→    margin-top: 0.6rem;
   216→}
   217→
   218→/* ===== STATUS ===== */
   219→.ctrl-status {
   220→    color: var(--ctrl-status);
   221→    font-size: 0.78em;
   222→    margin-top: 0.5rem;
   223→    min-height: 1.2rem;
   224→}
   225→
   226→/* ===== STATE ===== */
   227→.is-hidden { display: none; }
   228→
   229→/* ===== REDUCED MOTION ===== */
   230→@media (prefers-reduced-motion: reduce) {
   231→    .ctrl-btn,
   232→    .ctrl-radio-label,
   233→    input[type="number"],
   234→    input[type="text"] {
   235→        transition: none;
   236→    }
   237→}
