    30→    font-family: var(--font-family-heading);
    31→    font-size: clamp(1.4em, 3.5vw, 2.4em);
    32→    font-weight: bold;
    33→    line-height: 1.2;
    34→    margin: 0;
    35→    padding: var(--space-md) var(--space-sm);
