     1→/**
     2→ * border-effect.css — Animated Conic Gradient Border
     3→ * =====================================================
     4→ * Creates a rotating conic-gradient border effect using CSS animations.
     5→ * Uses CSS custom properties for easy customisation.
     6→ *
     7→ * Usage:
     8→ *   <div class="border-effect-wrap">
     9→ *     <div class="border-effect" aria-hidden="true"></div>
    10→ *     <button class="border-effect-btn">Label</button>
    11→ *   </div>
    12→ *
    13→ * The .border-effect element is purely decorative (aria-hidden).
    14→ * The adjacent button sits above it via z-index.
    15→ */
    16→
    17→/* ===== WRAPPER ===== */
    18→.border-effect-wrap {
    19→    align-items: center;
    20→    display: flex;
    21→    justify-content: center;
    22→    position: relative;
    23→}
    24→
    25→/* ===== SHARED: glow layer + button ===== */
    26→.border-effect,
    27→.border-effect-btn {
    28→    border-radius: var(--border-radius);
    29→    height: 100%;
    30→    max-height: 7.5rem;     /* 120px */
    31→    max-width: 8.75rem;     /* 140px */
    32→    overflow: hidden;
    33→    position: absolute;
    34→    width: 100%;
    35→}
    36→
    37→/* ===== GLOW LAYER ===== */
    38→/* Blurred version — creates the outer glow effect */
    39→.border-effect {
    40→    filter: blur(var(--border-blur));
    41→    z-index: 0;
    42→}
    43→
    44→/* Rotating conic gradient — shared by glow and clean border layers */
    45→.border-effect::before,
    46→.border-effect-btn::before {
    47→    animation: border-effect-rotate var(--animation-duration) linear infinite;
    48→    background-image: conic-gradient(
    49→        rgb(0 0 0 / 0),
    50→        var(--color-btn-primary),
    51→        rgb(0 0 0 / 0) 25%
    52→    );
    53→    background-position: 0 0;
    54→    background-repeat: no-repeat;
    55→    content: '';
    56→    height: 99999px;
    57→    left: 50%;
    58→    position: absolute;
    59→    top: 50%;
    60→    transform: translate(-50%, -50%) rotate(0deg);
    61→    width: 99999px;
    62→    z-index: -2;
    63→}
    64→
    65→/* Inner fill — hides the gradient inside the button boundary */
    66→.border-effect::after {
    67→    background: transparent;
    68→    border-radius: calc(var(--border-radius) - 2px);
    69→    content: '';
    70→    height: calc(100% - 2 * var(--border-width));
    71→    left: var(--border-width);
    72→    position: absolute;
    73→    top: var(--border-width);
    74→    width: calc(100% - 2 * var(--border-width));
    75→    z-index: -1;
    76→}
    77→
    78→/* ===== BUTTON (sits above glow layer) ===== */
    79→.border-effect-btn {
    80→    cursor: pointer;
    81→    max-height: 7.5rem;
    82→    max-width: 8.75rem;
    83→    position: relative;
    84→    z-index: 1;
    85→}
    86→
    87→.border-effect-btn:hover  { opacity: 0.95; }
    88→.border-effect-btn:active { opacity: 0.85; }
    89→
    90→.border-effect-btn:focus-visible {
    91→    outline: 2px solid var(--color-focus);
    92→    outline-offset: 2px;
    93→}
    94→
    95→/* ===== ANIMATION ===== */
    96→@keyframes border-effect-rotate {
    97→    from { transform: translate(-50%, -50%) rotate(0deg); }
    98→    to   { transform: translate(-50%, -50%) rotate(1turn); }
    99→}
   100→
   101→/* ===== BREAKPOINTS ===== */
   102→@media (min-width: 480px) {
   103→    .border-effect,
   104→    .border-effect-btn {
   105→        max-height: 9.375rem;    /* 150px */
   106→        max-width: 11.25rem;     /* 180px */
   107→    }
   108→}
   109→
   110→@media (min-width: 768px) {
   111→    .border-effect,
   112→    .border-effect-btn {
   113→        max-height: 12.5rem;     /* 200px */
   114→        max-width: 15.625rem;    /* 250px */
   115→    }
   116→}
   117→
   118→/* ===== ACCESSIBILITY ===== */
   119→@media (prefers-reduced-motion: reduce) {
   120→    .border-effect::before,
   121→    .border-effect-btn::before {
   122→        animation: none;
   123→    }
   124→}
   125→

