     1→/**
     2→ * play.css — Playlist page styles
     3→ * ================================
     4→ * Full-bleed black grid of SoundCloud playlist thumbnails.
     5→ * Mobile-first: 2 columns base → 6 columns at desktop.
     6→ */
     7→
     8→/* ===== RESET ===== */
     9→*,
    10→*::before,
    11→*::after {
    12→    box-sizing: border-box;
    13→    margin: 0;
    14→    padding: 0;
    15→}
    16→
    17→/* ===== PAGE ===== */
    18→html,
    19→body {
    20→    background: #000000;
    21→    min-height: 100%;
    22→}
    23→
    24→body {
    25→    font-family: Arial, Helvetica, sans-serif;
    26→}
    27→
    28→/* ===== LAYOUT WRAPPER ===== */
    29→.play-grid-wrap {
    30→    margin-inline: auto;
    31→    max-width: 1240px;
    32→    min-width: 320px;
    33→    padding: 60px 20px 40px;
    34→}
    35→
    36→/* ===== GRID ===== */
    37→/* Mobile: 2 columns */
    38→.play-grid {
    39→    display: grid;
    40→    gap: 0.33rem;
    41→    grid-template-columns: repeat(2, 1fr);
    42→}
    43→
    44→/* Desktop: 6 columns */
    45→@media (min-width: 768px) {
    46→    .play-grid {
    47→        grid-template-columns: repeat(6, 1fr);
    48→    }
    49→}
    50→
    51→/* ===== PLAYLIST CARD ===== */
    52→.playlist-card {
    53→    color: rgb(153, 153, 153);
    54→    display: block;
    55→    position: relative;
    56→    text-decoration: none;
    57→}
    58→
    59→/* Square aspect ratio — matches the 1:1 artwork */
    60→.playlist-card-inner {
    61→    aspect-ratio: 1;
    62→    overflow: hidden;
    63→    position: relative;
    64→}
    65→
    66→/* Gradient scrim so title is always legible on light artwork */
    67→.playlist-card-inner::before {
    68→    background: linear-gradient(to bottom, rgb(0 0 0 / 0.55) 0%, transparent 55%);
    69→    content: '';
    70→    inset: 0;
    71→    position: absolute;
    72→    z-index: 1;
    73→}
    74→
    75→/* ===== THUMBNAIL ===== */
    76→.playlist-card-img {
    77→    display: block;
    78→    height: 100%;
    79→    object-fit: cover;
    80→    transition: transform 0.3s ease, opacity 0.3s ease;
    81→    width: 100%;
    82→}
    83→
    84→/* ===== TITLE OVERLAY ===== */
    85→.playlist-card-title {
    86→    color: rgb(153, 153, 153);
    87→    font-size: 0.7em;
    88→    font-weight: normal;
    89→    left: 10px;
    90→    line-height: 1.3;
    91→    position: absolute;
    92→    right: 10px;
    93→    top: 10px;
    94→    transition: color 0.15s ease;
    95→    z-index: 2;
    96→}
    97→
    98→/* ===== STATES ===== */
    99→.playlist-card:hover .playlist-card-title,
   100→.playlist-card:focus .playlist-card-title,
   101→.playlist-card:active .playlist-card-title {
   102→    color: #ffffff;
   103→}
   104→
   105→.playlist-card:hover .playlist-card-img,
   106→.playlist-card:focus .playlist-card-img {
   107→    opacity: 0.85;
   108→    transform: scale(1.03);
   109→}
   110→
   111→.playlist-card:focus {
   112→    outline: 2px solid #ffffff;
   113→    outline-offset: 2px;
   114→}
   115→
   116→/* ===== REDUCED MOTION ===== */
   117→@media (prefers-reduced-motion: reduce) {
   118→    .playlist-card-img {
   119→        transition: none;
   120→    }
   121→
   122→    .playlist-card-title {
   123→        transition: none;
   124→    }
   125→}
   126→

