     1→/**
     2→ * components.css — Reusable UI Components
     3→ * ==========================================
     4→ * Header, logo, and other shared UI components.
     5→ * Mobile-first: base styles for smallest screen; min-width queries upward.
     6→ *
     7→ * Load order: after global.css, before page-specific CSS.
     8→ */
     9→
    10→/* ===== HEADER ===== */
    11→/* Mobile base */
    12→header {
    13→    align-items: center;
    14→    background-color: var(--color-bg);
    15→    border-bottom: var(--border-width) solid var(--color-border);
    16→    display: flex;
    17→    justify-content: center;
    18→    padding: var(--space-sm) var(--space-md);
    19→    width: 100%;
    20→}
    21→
    22→header a {
    23→    align-items: center;
    24→    color: inherit;
    25→    display: flex;
    26→    justify-content: center;
    27→    text-decoration: none;
    28→    transition: opacity var(--transition-fast) ease;
    29→}
    30→
    31→header a:hover { opacity: 0.8; }
    32→
    33→header a:focus-visible {
    34→    outline: 2px solid var(--color-focus);
    35→    outline-offset: 2px;
    36→}
    37→
    38→/* ===== LOGO ===== */
    39→/* Mobile base */
    40→.logo {
    41→    display: block;
    42→    height: 2.5rem;     /* 40px */
    43→    max-width: 400px;
    44→    width: auto;
    45→}
    46→
    47→@media (min-width: 480px) {
    48→    header { padding: 0.75rem 1.5rem; }
    49→    .logo  { height: 3.125rem; }  /* 50px */
    50→}
    51→
    52→@media (min-width: 768px) {
    53→    header { padding: var(--space-md) var(--space-xl); }
    54→    .logo  { height: 3.75rem; }   /* 60px */
    55→}
    56→
    57→/* ===== MAIN LAYOUT ===== */
    58→/* Non-clock pages: flex column, no fixed height */
    59→main {
    60→    display: flex;
    61→    flex-direction: column;
    62→    min-height: calc(100vh - 6rem); /* approximate header clearance */
    63→    padding: var(--space-xl) 0;
    64→    width: 100%;
    65→}
    66→
    67→/* ===== TOOLTIP ===== */
    68→/* Usage: <span class="tooltip" data-tip="Label text">…</span> */
    69→.tooltip {
    70→    position: relative;
    71→}
    72→
    73→.tooltip::after {
    74→    background: var(--color-bg-raised);
    75→    border: 1px solid var(--color-border-subtle);
    76→    border-radius: var(--border-radius-sm);
    77→    color: var(--color-text);
    78→    content: attr(data-tip);
    79→    font-size: 0.8em;
    80→    left: 50%;
    81→    line-height: 1.4;
    82→    max-width: 16rem;
    83→    opacity: 0;
    84→    padding: var(--space-xs) var(--space-sm);
    85→    pointer-events: none;
    86→    position: absolute;
    87→    top: calc(100% + 0.5rem);
    88→    transform: translateX(-50%);
    89→    transition: opacity var(--transition-fast) ease;
    90→    white-space: nowrap;
    91→    z-index: 100;
    92→}
    93→
    94→.tooltip:hover::after,
    95→.tooltip:focus-visible::after {
    96→    opacity: 1;
    97→}
    98→
    99→@media (prefers-reduced-motion: reduce) {
   100→    .tooltip::after { transition: none; }
   101→}
   102→
   103→/* ===== ALERT ===== */
   104→/* Usage: <div class="alert mod-info" role="alert">…</div> */
   105→.alert {
   106→    border-left: 4px solid var(--color-border);
